def search_in_hadith(ns):
    hits=[]
    for h in hdata:
        t=h.get('hadithTxt') or h.get('Matn') or ''
        if not isinstance(t,str): 
            continue
        nt=normalize(t)
        if ns in nt:
            hits.append(h)
        else:
            toks=ns.split()
            if sum(tok in nt for tok in toks)>=max(3, int(len(toks)*0.6)):
                hits.append(h)
    return hits

